function uup_create_upload_directory() {
    $upload_dir = WP_CONTENT_DIR . '/uploads/user-files';
    if ( ! file_exists( $upload_dir ) ) {
        wp_mkdir_p( $upload_dir );
    }
}
add_action( 'init', 'uup_create_upload_directory' );

function uup_handle_file_upload() {
    if ( isset( $_POST['uup_submit_upload'] ) ) {
        if ( ! is_user_logged_in() ) {
            echo '<div>Only logged in users can upload files.</div>';
            return;
        }

        $allowed_extensions = array( 'jpg', 'jpeg', 'png', 'gif', 'pdf', 'doc', 'docx' );
        $upload_dir = WP_CONTENT_DIR . '/uploads/user-files/';

        // Handle Profile Picture Upload
        if ( isset( $_FILES['uup_profile_picture'] ) && $_FILES['uup_profile_picture']['error'] === 0 ) {
            $profile_info = pathinfo( $_FILES['uup_profile_picture']['name'] );
            $profile_ext  = strtolower( $profile_info['extension'] );
            if ( in_array( $profile_ext, $allowed_extensions ) ) {
                $profile_filename = uniqid( 'profile_' ) . '.' . $profile_ext;
                $profile_target   = $upload_dir . $profile_filename;
                if ( move_uploaded_file( $_FILES['uup_profile_picture']['tmp_name'], $profile_target ) ) {
                    echo '<div>Profile picture uploaded successfully: ' . esc_html( $profile_filename ) . '</div>';
                } else {
                    echo '<div>Error uploading profile picture.</div>';
                }
            } else {
                echo '<div>Invalid file type for profile picture.</div>';
            }
        }

        // Handle Document File Upload
        if ( isset( $_FILES['uup_document_file'] ) && $_FILES['uup_document_file']['error'] === 0 ) {
            $doc_info = pathinfo( $_FILES['uup_document_file']['name'] );
            $doc_ext  = strtolower( $doc_info['extension'] );
            if ( in_array( $doc_ext, $allowed_extensions ) ) {
                $doc_filename = uniqid( 'document_' ) . '.' . $doc_ext;
                $doc_target   = $upload_dir . $doc_filename;
                if ( move_uploaded_file( $_FILES['uup_document_file']['tmp_name'], $doc_target ) ) {
                    echo '<div>Document uploaded successfully: ' . esc_html( $doc_filename ) . '</div>';
                } else {
                    echo '<div>Error uploading document file.</div>';
                }
            } else {
                echo '<div>Invalid file type for document file.</div>';
            }
        }
    }
}

function uup_upload_form_shortcode() {
    ob_start();
    uup_handle_file_upload();
    if ( ! is_user_logged_in() ) {
        echo '<div>Please log in to upload files.</div>';
        return ob_get_clean();
    }
    ?>
    <form method="post" enctype="multipart/form-data">
        <p>
            <label for="uup_profile_picture">Upload Profile Picture:</label>
            <input type="file" name="uup_profile_picture" id="uup_profile_picture">
        </p>
        <p>
            <label for="uup_document_file">Upload Document:</label>
            <input type="file" name="uup_document_file" id="uup_document_file">
        </p>
        <p>
            <input type="submit" name="uup_submit_upload" value="Upload Files">
        </p>
    </form>
    <?php
    return ob_get_clean();
}
add_shortcode( 'user_upload_form', 'uup_upload_form_shortcode' );
?>